using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability by fetching and extracting content from search result pages.
/// </summary>
public sealed partial class WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
{
    [Description("Search the web for information on a given query. Returns a list of result snippets with titles and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);
        logger.LogInformation("Searching web for: {Query}", query);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();
            return ParseSearchResults(html, maxResults);
        }
        catch (Exception ex)
        {
            logger.LogWarning(ex, "Web search failed for query: {Query}", query);
            return $"Search failed: {ex.Message}. Try a different query or check connectivity.";
        }
    }

    [Description("Fetch and extract the main text content from a specific URL.")]
    public async Task<string> FetchPageContentAsync(
        [Description("The URL to fetch content from")] string url)
    {
        logger.LogInformation("Fetching page: {Url}", url);

        try
        {
            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();
            var text = StripHtml(html);

            // Limit to ~3000 chars to avoid overwhelming the context
            if (text.Length > 3000)
                text = text[..3000] + "\n... [content truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful content from this page."
                : text;
        }
        catch (Exception ex)
        {
            logger.LogWarning(ex, "Failed to fetch page: {Url}", url);
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html, int maxResults)
    {
        var sb = new StringBuilder();
        var resultPattern = ResultRegex();
        var matches = resultPattern.Matches(html);

        if (matches.Count == 0)
            return "No results found. Try rephrasing the query.";

        var count = 0;
        foreach (Match match in matches)
        {
            if (count >= maxResults) break;

            var resultUrl = match.Groups["url"].Value;
            var title = StripHtml(match.Groups["title"].Value).Trim();
            var snippet = match.Groups.Count > 3
                ? StripHtml(match.Groups["snippet"].Value).Trim()
                : "";

            if (string.IsNullOrWhiteSpace(title)) continue;

            count++;
            sb.AppendLine($"[{count}] {title}");
            if (!string.IsNullOrWhiteSpace(resultUrl))
                sb.AppendLine($"    URL: {resultUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return count > 0
            ? sb.ToString()
            : "No results found. Try rephrasing the query.";
    }

    private static string StripHtml(string html)
    {
        var text = TagRegex().Replace(html, " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = WhitespaceRegex().Replace(text, " ");
        return text.Trim();
    }

    [GeneratedRegex("""<a[^>]+href="(?<url>[^"]*)"[^>]*class="[^"]*result__a[^"]*"[^>]*>(?<title>.*?)</a>.*?<a[^>]+class="[^"]*result__snippet[^"]*"[^>]*>(?<snippet>.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// </summary>
public sealed class NoteTool(ILogger<NoteTool> logger)
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a topic tag and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short topic tag for the note (e.g., 'definition', 'history', 'key-finding')")] string topic,
        [Description("The content of the note")] string content)
    {
        var note = new Note(topic, content, DateTimeOffset.UtcNow);
        _notes.Add(note);
        logger.LogInformation("Note added: [{Topic}] ({Length} chars)", topic, content.Length);
        return $"Note #{_notes.Count} saved under topic '{topic}'.";
    }

    [Description("Retrieve all saved research notes, optionally filtered by topic tag.")]
    public string GetNotes(
        [Description("Optional topic filter. Leave empty to get all notes.")] string? topic = null)
    {
        var filtered = string.IsNullOrWhiteSpace(topic)
            ? _notes
            : _notes.Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
            return string.IsNullOrWhiteSpace(topic)
                ? "No notes saved yet."
                : $"No notes found for topic '{topic}'.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({filtered.Count}) ===");
        for (var i = 0; i < filtered.Count; i++)
        {
            var note = filtered[i];
            sb.AppendLine($"--- Note #{i + 1} [{note.Topic}] ({note.Timestamp:HH:mm:ss}) ---");
            sb.AppendLine(note.Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Get a count of how many notes have been saved so far, grouped by topic.")]
    public string GetNoteSummary()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var groups = _notes.GroupBy(n => n.Topic, StringComparer.OrdinalIgnoreCase);
        var sb = new StringBuilder();
        sb.AppendLine($"Total notes: {_notes.Count}");
        foreach (var group in groups)
        {
            sb.AppendLine($"  [{group.Key}]: {group.Count()} note(s)");
        }

        return sb.ToString();
    }

    private sealed record Note(string Topic, string Content, DateTimeOffset Timestamp);
}

