using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// </summary>
public sealed class NoteTool(ILogger<NoteTool> logger)
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a topic tag and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short topic tag for the note (e.g., 'definition', 'history', 'key-finding')")] string topic,
        [Description("The content of the note")] string content)
    {
        var note = new Note(topic, content, DateTimeOffset.UtcNow);
        _notes.Add(note);
        logger.LogInformation("Note added: [{Topic}] ({Length} chars)", topic, content.Length);
        return $"Note #{_notes.Count} saved under topic '{topic}'.";
    }

    [Description("Retrieve all saved research notes, optionally filtered by topic tag.")]
    public string GetNotes(
        [Description("Optional topic filter. Leave empty to get all notes.")] string? topic = null)
    {
        var filtered = string.IsNullOrWhiteSpace(topic)
            ? _notes
            : _notes.Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
            return string.IsNullOrWhiteSpace(topic)
                ? "No notes saved yet."
                : $"No notes found for topic '{topic}'.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({filtered.Count}) ===");
        for (var i = 0; i < filtered.Count; i++)
        {
            var note = filtered[i];
            sb.AppendLine($"--- Note #{i + 1} [{note.Topic}] ({note.Timestamp:HH:mm:ss}) ---");
            sb.AppendLine(note.Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Get a count of how many notes have been saved so far, grouped by topic.")]
    public string GetNoteSummary()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var groups = _notes.GroupBy(n => n.Topic, StringComparer.OrdinalIgnoreCase);
        var sb = new StringBuilder();
        sb.AppendLine($"Total notes: {_notes.Count}");
        foreach (var group in groups)
        {
            sb.AppendLine($"  [{group.Key}]: {group.Count()} note(s)");
        }

        return sb.ToString();
    }

    private sealed record Note(string Topic, string Content, DateTimeOffset Timestamp);
}

