using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Dependency Injection ---
var services = new ServiceCollection();

services.AddLogging(builder => builder
    .AddConsole()
    .SetMinimumLevel(LogLevel.Information));

services.AddHttpClient<WebSearchTool>();

services.AddSingleton<WebSearchTool>();
services.AddSingleton<NoteTool>();

services.AddChatClient(builder => builder
    .UseLogging()
    .Use(new OpenAIClient(apiKey).AsChatClient(modelId)));

var provider = services.BuildServiceProvider();
var chatClient = provider.GetRequiredService<IChatClient>();
var logger = provider.GetRequiredService<ILogger<Program>>();
var webSearch = provider.GetRequiredService<WebSearchTool>();
var noteTool = provider.GetRequiredService<NoteTool>();

// --- Register Tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchPageContentAsync),
    AIFunctionFactory.Create(noteTool.AddNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
    AIFunctionFactory.Create(noteTool.GetNoteSummary),
};

// --- Build Agent ---
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly and produce a well-organized summary.

        Follow this workflow:
        1. SEARCH: Use SearchWebAsync to find relevant information about the topic. Run 2-3 different searches with varied queries.
        2. DEEP DIVE: Use FetchPageContentAsync on the most promising URLs to get detailed content.
        3. TAKE NOTES: Use AddNote to save key findings as you go. Use descriptive topic tags like 'definition', 'history', 'key-fact', 'statistic', 'controversy', etc.
        4. REVIEW: Use GetNotes to review all your collected notes.
        5. SUMMARIZE: Produce a final, well-structured summary that synthesizes your notes into a coherent report.

        Guidelines:
        - Be thorough but focused. Prioritize quality over quantity.
        - Always take notes before summarizing — do not try to remember everything.
        - Cite sources where possible.
        - If a search or page fetch fails, try alternative queries or URLs.
        - Your final summary should be clearly structured with sections.
        """,
};

// --- Get Topic and Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
    Console.WriteLine($"Researching: {topic}");
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine();
Console.WriteLine("Agent is researching... (this may take a minute)");
Console.WriteLine(new string('─', 50));

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 15,
    ModelOptions = new ChatOptions
    {
        Temperature = 0f,
        Tools = [.. tools],
    },
};

// Stream the agent's final response
await foreach (var update in agent.InvokeStreamingAsync(history, options))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Research complete.");

